import{_ as t,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Cloudflare R2 Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/cloudflare-r2.md","filePath":"ta/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"ta/upload/cloudflare-r2.md"};function c(u,e,s,h,b,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="cloudflare-r2-channel-சேர்க்கவும்" tabindex="-1">Cloudflare R2 Channel சேர்க்கவும் <a class="header-anchor" href="#cloudflare-r2-channel-சேர்க்கவும்" aria-label="Permalink to &quot;Cloudflare R2 Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="எப்போது-பயன்படுத்துவது" tabindex="-1">எப்போது பயன்படுத்துவது <a class="header-anchor" href="#எப்போது-பயன்படுத்துவது" aria-label="Permalink to &quot;எப்போது பயன்படுத்துவது&quot;">​</a></h2><p>Cloudflare R2 பயன்படுத்தலாம், நீங்கள்:</p><ul><li>ImgBed site ஏற்கனவே Cloudflare-ல் deploy செய்து, அதே Cloudflare account-இன் R2 bucket-ல் files சேமிக்க விரும்பினால்.</li><li>தனியாக S3 endpoint, access key, secret key அமைக்க விரும்பவில்லை என்றால்.</li><li>Worker அல்லது Pages R2 binding மூலம் குறைந்த setup-இல் reads/writes செல்ல வேண்டும் என்றால்.</li></ul><p>சுருக்கமாக:</p><p>R2 channel ImgBed admin panel-ல் manual ஆக உருவாக்கப்படாது. முதலில் Cloudflare project-க்கு R2 bucket bind செய்ய வேண்டும்; binding variable name கண்டிப்பாக <code>img_r2</code> ஆக இருக்க வேண்டும்.</p><h2 id="தொடங்குவதற்கு-முன்-தேவையானவை" tabindex="-1">தொடங்குவதற்கு முன் தேவையானவை <a class="header-anchor" href="#தொடங்குவதற்கு-முன்-தேவையானவை" aria-label="Permalink to &quot;தொடங்குவதற்கு முன் தேவையானவை&quot;">​</a></h2><ul><li>Cloudflare account.</li><li>ஏற்கனவே உருவாக்கப்பட்ட R2 bucket.</li><li>ImgBed deploy செய்யப்பட்ட Cloudflare project-ஐ manage செய்ய permission.</li></ul><h2 id="cloudflare-ல்-configure-செய்யவும்" tabindex="-1">Cloudflare-ல் Configure செய்யவும் <a class="header-anchor" href="#cloudflare-ல்-configure-செய்யவும்" aria-label="Permalink to &quot;Cloudflare-ல் Configure செய்யவும்&quot;">​</a></h2><h3 id="_1-r2-bucket-உருவாக்கவும்" tabindex="-1">1. R2 Bucket உருவாக்கவும் <a class="header-anchor" href="#_1-r2-bucket-உருவாக்கவும்" aria-label="Permalink to &quot;1. R2 Bucket உருவாக்கவும்&quot;">​</a></h3><ol><li>Cloudflare Dashboard-ல் log in செய்யவும்.</li><li><code>R2 Object Storage</code> திறக்கவும்.</li><li>Create bucket கிளிக் செய்யவும்.</li><li>bucket name தேர்வு செய்யவும், உதா. <code>imgbed</code>.</li></ol><p>uploaded files இந்த bucket-ல் சேமிக்கப்படும்.</p><p><img src="'+t+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bucket-ஐ-imgbed-project-க்கு-bind-செய்யவும்" tabindex="-1">2. Bucket-ஐ ImgBed Project-க்கு Bind செய்யவும் <a class="header-anchor" href="#_2-bucket-ஐ-imgbed-project-க்கு-bind-செய்யவும்" aria-label="Permalink to &quot;2. Bucket-ஐ ImgBed Project-க்கு Bind செய்யவும்&quot;">​</a></h3><p>deployment type அடிப்படையில் binding location தேர்வு செய்யவும்:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>binding add செய்யும் போது முக்கிய fields:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>நீங்கள் உருவாக்கிய bucket-ஐ தேர்வு செய்யவும்.</td></tr></tbody></table><p>Variable name சரியாக <code>img_r2</code> ஆகவே இருக்க வேண்டும். R2 files upload, read, delete அனைத்தும் இந்த binding name-ஐ சார்ந்தவை.</p><h3 id="_3-project-ஐ-மீண்டும்-deploy-செய்யவும்" tabindex="-1">3. Project-ஐ மீண்டும் Deploy செய்யவும் <a class="header-anchor" href="#_3-project-ஐ-மீண்டும்-deploy-செய்யவும்" aria-label="Permalink to &quot;3. Project-ஐ மீண்டும் Deploy செய்யவும்&quot;">​</a></h3><p>binding save செய்த பிறகு ImgBed-ஐ redeploy செய்யவும். அப்போதுதான் Worker அல்லது Pages runtime <code>img_r2</code> அணுக முடியும்.</p><h2 id="imgbed-ல்-என்ன-தெரியும்" tabindex="-1">ImgBed-ல் என்ன தெரியும் <a class="header-anchor" href="#imgbed-ல்-என்ன-தெரியும்" aria-label="Permalink to &quot;ImgBed-ல் என்ன தெரியும்&quot;">​</a></h2><p>R2 binding கிடைத்த பிறகு திறக்கவும்:</p><ol><li>System Settings.</li><li>Upload Settings.</li><li><code>Cloudflare R2</code> channel.</li></ol><p>system ஒரு fixed channel-ஐ தானாக உருவாக்கும்:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>இது fixed binding channel. இதை உருவாக்க Add Channel கிளிக் செய்ய வேண்டியதில்லை; regular channel போல delete செய்யவும் முடியாது.</p><h2 id="admin-panel-ல்-திருத்தக்கூடிய-fields" tabindex="-1">Admin Panel-ல் திருத்தக்கூடிய Fields <a class="header-anchor" href="#admin-panel-ல்-திருத்தக்கூடிய-fields" aria-label="Permalink to &quot;Admin Panel-ல் திருத்தக்கூடிய Fields&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>பயன்பாடு</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>R2 upload selection-ல் பங்கேற்க வேண்டுமா என்பதை கட்டுப்படுத்தும்.</td><td>Yes</td></tr><tr><td>Account ID</td><td>quota limits enabled ஆகும் போது official R2 usage query செய்ய மட்டும்.</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Bucket name</td><td>quota limits enabled ஆகும் போது official R2 usage query செய்ய மட்டும்.</td><td>Recommended when quota limits are enabled</td></tr><tr><td>Quota limit</td><td>capacity அடிப்படையில் இந்த R2 channel upload selection-ல் பங்கேற்க வேண்டுமா என்பதை கட்டுப்படுத்தும்.</td><td>No</td></tr><tr><td>Threshold</td><td>usage குறிப்பிட்ட percentage அடைந்த பிறகு இந்த channel-ல் write செய்வதை நிறுத்தும்.</td><td>Required when quota limits are enabled</td></tr></tbody></table><p>Cloudflare dashboard-ல் account information panel-இல் இருந்து Account ID copy செய்யலாம். ImgBed R2 quota usage query/enforce செய்ய வேண்டும் என்றால் மட்டும் நிரப்பவும்.</p><p><img src="'+a+'" alt="Get the Account ID" loading="lazy"></p><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Cloudflare-ல் R2 bucket உருவாக்கவும்.</li><li>ImgBed project-க்கான Cloudflare settings திறக்கவும்.</li><li>R2 bucket binding add செய்யவும்.</li><li><code>Variable name</code>-ஐ <code>img_r2</code> ஆக அமைக்கவும்.</li><li>உருவாக்கிய R2 bucket தேர்வு செய்யவும்.</li><li>binding save செய்து ImgBed redeploy செய்யவும்.</li><li>ImgBed -&gt; System Settings -&gt; Upload Settings-க்கு திரும்பவும்.</li><li><code>Cloudflare R2</code> channel தெரிகிறதா, enabled ஆக உள்ளதா பார்க்கவும்.</li></ol><p>capacity அடிப்படையில் R2 upload selection-ல் பங்கேற்க வேண்டும் என்றால் quota limit enable செய்து Account ID, bucket name, quota limit, threshold நிரப்பி save செய்யவும்.</p><p><img src="'+d+'" alt="Configure quota limits" loading="lazy"></p><h2 id="verify-செய்வது" tabindex="-1">Verify செய்வது <a class="header-anchor" href="#verify-செய்வது" aria-label="Permalink to &quot;Verify செய்வது&quot;">​</a></h2><ul><li>fixed <code>Cloudflare R2</code> channel Upload Settings-ல் தெரியும்.</li><li>channel card enabled என காட்டும்.</li><li>சிறிய test file upload ஆகி returned link திறக்கும்.</li><li>file திறக்கும் போது <code>R2 database binding is not configured</code> வந்தால் runtime-க்கு <code>img_r2</code> binding கிடைக்கவில்லை. Cloudflare-ல் binding name சரிபார்த்து project redeploy செய்யவும்.</li></ul>',37)])])}const k=l(n,[["render",c]]);export{f as __pageData,k as default};
